import{_ as t,o as e,c as o,R as a}from"./chunks/framework.PZ77rLUR.js";const g=JSON.parse('{"title":"1.Go数据类型","description":"","frontmatter":{},"headers":[],"relativePath":"guide/go/7-go语言数据类型.md","filePath":"guide/go/7-go语言数据类型.md","lastUpdated":1701229860000}'),d={name:"guide/go/7-go语言数据类型.md"},r=a('<h1 id="_1-go数据类型" tabindex="-1">1.Go数据类型 <a class="header-anchor" href="#_1-go数据类型" aria-label="Permalink to &quot;1.Go数据类型&quot;">​</a></h1><p>Go语言是一种静态类型的编程语言，在Go编程语言中，数据类型用于声明函数和变量。数据类型的出现是为了把数据分成所需内存大小不同的数据，编程的时候需要用大数据的时候才需要申请大内存，就可以充分利用内存。编译器在进行编译的时候，就要知道每个值的类型，这样编译器就知道要为这个值分配多少内存，并且知道这段分配的内存表示什么。</p><table><thead><tr><th>类型</th><th>详解</th></tr></thead><tbody><tr><td>布尔型</td><td>布尔型的值只可以是常量 true 或者 false。</td></tr><tr><td>数字类型</td><td>整型 int 和浮点型 float。Go 语言支持整型和浮点型数字，并且支持复数，其中位的运算采用补码。</td></tr><tr><td>字符串类型</td><td>字符串就是一串固定长度的字符连接起来的字符序列。Go 的字符串是由单个字节连接起来的。Go 语言的字符串的字节使用 UTF-8 编码标识 Unicode 文本。</td></tr><tr><td>派生类型</td><td>(a) 指针类型（Pointer）(b) 数组类型© 结构化类型(struct)(d) Channel 类型(e) 函数类型(f) 切片类型(g) 接口类型（interface）(h) Map 类型</td></tr></tbody></table>',3),_=[r];function n(s,c,i,h,l,p){return e(),o("div",null,_)}const u=t(d,[["render",n]]);export{g as __pageData,u as default};
